// Custom hero definitions — stores hero templates that players can roll for
// Each hero has: id, name, description, gemCost (to roll), base stats, rarity

const STORAGE_KEY = "custom_hero_defs_v1";

export const DEFAULT_HERO_STATS = {
  hp: 200,
  attack: 25,
  defense: 15,
  speed: 10, // movement speed
  attack_speed: 1.0, // attacks per second
  range: 1, // melee=1, ranged>1
  crit_chance: 5, // percent
  dodge_chance: 5 // percent
};

function getStore() {
  try {return JSON.parse(localStorage.getItem(STORAGE_KEY) || "[]");}
  catch {return [];}
}

function saveStore(data) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
}

export function getAllCustomHeroes() {
  return getStore();
}

export function getCustomHero(id) {
  return getStore().find((h) => h.id === id) || null;
}

export function saveCustomHero(hero) {
  const store = getStore();
  const idx = store.findIndex((h) => h.id === hero.id);
  if (idx >= 0) store[idx] = hero;else
  store.push(hero);
  saveStore(store);
}

export function deleteCustomHero(id) {
  const store = getStore().filter((h) => h.id !== id);
  saveStore(store);
}

export function createNewHero(name) {
  return {
    id: `hero_${Date.now()}_${Math.random().toString(36).slice(2)}`,
    name: name || "New Hero",
    description: "",
    rarity: "common",
    gem_cost: 100,
    is_rollable: true,
    ...DEFAULT_HERO_STATS
  };
}
